import React from 'react';
import { Leaf, Bell, User, ShoppingCart, Search } from 'lucide-react';

const Header = () => {
  return (
    <header style={styles.header}>
      <div style={styles.logoContainer}>
        <Leaf color="#2ECC71" size={28} />
        <h1 style={styles.logoText}>EcoDespensa</h1>
      </div>

      <div style={styles.searchContainer}>
        <Search size={18} color="#aaa" style={{ marginLeft: 15 }} />
        <input 
          type="text" 
          placeholder="¿Qué buscas en tu despensa?" 
          style={styles.searchInput}
        />
      </div>

      <div style={styles.actions}>
        <button style={styles.iconButton}><Bell size={22} color="#777" /></button>
        <button style={styles.iconButton}><ShoppingCart size={22} color="#777" /></button>
        <button style={styles.iconButton}><User size={22} color="#777" /></button>
      </div>
    </header>
  );
};

const styles = {
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '15px 30px',
    backgroundColor: '#FFFFFF',
    borderBottom: '1px solid #eee',
    boxShadow: '0 2px 10px rgba(0,0,0,0.02)',
    position: 'sticky',
    top: 0,
    zIndex: 100
  },
  logoContainer: {
    display: 'flex',
    alignItems: 'center',
    gap: '10px'
  },
  logoText: {
    color: '#2ECC71',
    fontSize: '22px',
    fontWeight: '700',
    margin: 0
  },
  searchContainer: {
    display: 'flex',
    alignItems: 'center',
    backgroundColor: '#F5F5F5',
    borderRadius: '25px',
    width: '400px',
    border: '1px solid #eee'
  },
  searchInput: {
    border: 'none',
    backgroundColor: 'transparent',
    padding: '12px 15px',
    width: '100%',
    outline: 'none',
    fontSize: '15px'
  },
  actions: {
    display: 'flex',
    gap: '15px'
  },
  iconButton: {
    background: 'none',
    border: 'none',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '8px',
    borderRadius: '50%',
    transition: 'background 0.2s'
  }
};

export default Header;
